#include <stdio.h>

int main(void) {
    /* for loop: known iterations */
    printf("for: ");
    for (int i = 0; i < 5; i++) {
        printf("%d ", i);
    }
    printf("\n"); /* 0 1 2 3 4 */

    /* while loop: condition-based */
    printf("while: ");
    int n = 1;
    while (n <= 16) {
        printf("%d ", n);
        n *= 2;
    }
    printf("\n"); /* 1 2 4 8 16 */

    /* do-while: executes at least once */
    printf("do-while: ");
    int x = 100;
    do {
        printf("%d ", x);
        x--;
    } while (x > 100); /* condition false immediately */
    printf("\n"); /* 100 (body ran once!) */

    /* do-while for input validation */
    int value;
    do {
        value = 42; /* simulate reading input */
    } while (value < 0);
    printf("valid: %d\n", value);

    /* while vs do-while: zero iterations */
    int count = 0;
    while (count > 0) {
        printf("never\n"); /* never executes */
    }

    return 0;
}

