#include <stdio.h>

int main(void) {
    /* break: exit loop early */
    printf("break: ");
    for (int i = 0; i < 10; i++) {
        if (i == 5) break;
        printf("%d ", i);
    }
    printf("\n"); /* 0 1 2 3 4 */

    /* continue: skip even numbers */
    printf("continue: ");
    for (int i = 0; i < 10; i++) {
        if (i % 2 == 0) continue;
        printf("%d ", i);
    }
    printf("\n"); /* 1 3 5 7 9 */

    /* continue in while -- be careful with counter */
    printf("while continue: ");
    int j = 0;
    while (j < 10) {
        j++;
        if (j % 2 == 0) continue;
        printf("%d ", j);
    }
    printf("\n"); /* 1 3 5 7 9 */

    /* break only exits innermost loop */
    for (int row = 0; row < 3; row++) {
        for (int col = 0; col < 3; col++) {
            if (col == 1) break; /* only breaks inner loop */
            printf("(%d,%d) ", row, col);
        }
    }
    printf("\n"); /* (0,0) (1,0) (2,0) */

    return 0;
}

