/* Pattern 2: Breaking out of nested loops */
void find_value(int matrix[3][3], int target) {
    for (int i = 0; i < 3; i++) {
        for (int j = 0; j < 3; j++) {
            if (matrix[i][j] == target) {
                printf("Found at (%d,%d)\n", i, j);
                goto done;  /* clean exit from both loops */
            }
        }
    }
    printf("Not found\n");
done:
    return;
}

