/* Duff's device: copy n bytes from src to dst */
void duff_copy(char *dst, const char *src, int n) {
    if (n <= 0) return;
    int iterations = (n + 7) / 8;
    switch (n % 8) {
        case 0: do { *dst++ = *src++;
        case 7:      *dst++ = *src++;
        case 6:      *dst++ = *src++;
        case 5:      *dst++ = *src++;
        case 4:      *dst++ = *src++;
        case 3:      *dst++ = *src++;
        case 2:      *dst++ = *src++;
        case 1:      *dst++ = *src++;
                } while (--iterations > 0);
    }
}

