int main(void) {
    int a = 1, b = 0;

    /* Dangling else: else binds to nearest if (if(b)) */
    printf("Dangling: ");
    if (a)
        if (b)
            printf("both true");
    else
        printf("b is false");  /* This prints (else binds to if(b)) */
    printf("\n");

    /* Clear intent 1: else with inner if */
    printf("Intent 1: ");
    if (a) {
        if (b) {
            printf("both true");
        } else {
            printf("a true, b false"); /* This prints */
        }
    }
    printf("\n");

    /* Clear intent 2: else with outer if */
    a = 0;
    printf("Intent 2: ");
    if (a) {
        if (b) {
            printf("both true");
        }
    } else {
        printf("a is false"); /* This prints */
    }
    printf("\n");

    return 0;
}

