/* State machine pattern */
typedef enum {
    STATE_INIT,
    STATE_RUNNING,
    STATE_DONE
} State;

void run_machine(void) {
    State s = STATE_INIT;
    int steps = 0;
    while (s != STATE_DONE) {
        switch (s) {
            case STATE_INIT:
                printf("Initializing...\n");
                s = STATE_RUNNING;
                break;
            case STATE_RUNNING:
                printf("Running step %d\n", steps++);
                if (steps >= 3) s = STATE_DONE;
                break;
            case STATE_DONE:
                break;
        }
    }
    printf("Done!\n");
}

int main(void) {
    printf("%s\n", color_name(COLOR_BLUE)); /* Blue */
    run_machine();
    return 0;
}

