#include <stdio.h>
#include <ctype.h>
#include <string.h>

/* Simple integer parser state machine */
typedef enum {
    PARSE_START,
    PARSE_SIGN,
    PARSE_DIGITS,
    PARSE_DONE,
    PARSE_ERROR
} ParseState;

int parse_int(const char *str, int *result) {
    ParseState state = PARSE_START;
    int sign = 1;
    int value = 0;
    int i = 0;
    int len = (int)strlen(str);

    while (state != PARSE_DONE && state != PARSE_ERROR) {
        char ch = (i < len) ? str[i] : '\0';

        switch (state) {
            case PARSE_START:
                if (ch == '+' || ch == '-') {
                    sign = (ch == '-') ? -1 : 1;
                    state = PARSE_SIGN;
                    i++;
                } else if (isdigit(ch)) {
                    state = PARSE_DIGITS;
                } else {
                    state = PARSE_ERROR;
                }
                break;

            case PARSE_SIGN:
                if (isdigit(ch)) {
                    state = PARSE_DIGITS;
                } else {
                    state = PARSE_ERROR;
                }
                break;

            case PARSE_DIGITS:
                if (isdigit(ch)) {
                    value = value * 10 + (ch - '0');
                    i++;
                } else if (ch == '\0') {
                    state = PARSE_DONE;
                } else {
                    state = PARSE_ERROR;
                }
                break;

            case PARSE_DONE:
            case PARSE_ERROR:
                break;
        }
    }

    if (state == PARSE_DONE) {
        *result = sign * value;
        return 1; /* success */
    }
    return 0; /* error */
}

int main(void) {
    int val;
    if (parse_int("-42", &val)) {
        printf("Parsed: %d\n", val); /* -42 */
    }
    if (parse_int("123", &val)) {
        printf("Parsed: %d\n", val); /* 123 */
    }
    if (!parse_int("12abc", &val)) {
        printf("Parse error\n"); /* error */
    }
    return 0;
}

